mapper.select:
SELECT
id, student_id, textbook_id, chapter_id, position,
material_type, title, url, content, minio_bucket,
minio_object_name, file_size, file_type, create_time, update_time
FROM extend_reading
WHERE student_id = #{studentId}
AND textbook_id = #{textbookId}

    AND chapter_id = #{chapterId}

ORDER BY create_time DESC
